import { useState } from 'react'
import Today from './pages/Today'
import Episodes from './pages/Episodes'
import Heart from './pages/Heart'
import Food from './pages/Food'
import Analytics from './pages/Analytics'
import More from './pages/More'
import Toast from './components/Toast'

const TABS = [
  { id:'today', label:'Today', icon:<svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><rect x="3" y="4" width="18" height="18" rx="2.5"/><path d="M16 2v4M8 2v4M3 10h18"/></svg> },
  { id:'episodes', label:'Events', icon:<svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z"/></svg> },
  { id:'heart', label:'Heart', icon:<svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78L12 21.23l7.78-7.78a5.5 5.5 0 0 0 0-7.78z"/></svg> },
  { id:'food', label:'Food', icon:<svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M12 2a10 10 0 1 0 0 20A10 10 0 0 0 12 2z"/><path d="M12 8v4l3 3"/></svg> },
  { id:'analytics', label:'Insights', icon:<svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/></svg> },
  { id:'more', label:'More', icon:<svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><circle cx="5" cy="12" r="1.5" fill="currentColor"/><circle cx="12" cy="12" r="1.5" fill="currentColor"/><circle cx="19" cy="12" r="1.5" fill="currentColor"/></svg> },
]

export default function App() {
  const [tab, setTab] = useState('today')
  const [toast, setToast] = useState(null)
  const showToast = (msg, color) => { setToast({msg,color}); setTimeout(()=>setToast(null),2500) }
  const p = { showToast }
  const pages = { today:<Today {...p}/>, episodes:<Episodes {...p}/>, heart:<Heart {...p}/>, food:<Food {...p}/>, analytics:<Analytics {...p}/>, more:<More {...p}/> }
  return (
    <>
      <div key={tab} className="fade-up">{pages[tab]}</div>
      <nav className="tab-bar">
        {TABS.map(t=>(
          <button key={t.id} className={`tab-item ${tab===t.id?'on':''}`} onClick={()=>setTab(t.id)}>
            <div className="tab-icon">{t.icon}</div>
            <span className="tab-label">{t.label}</span>
          </button>
        ))}
      </nav>
      {toast && <Toast message={toast.msg} color={toast.color}/>}
    </>
  )
}
